impl Solution { pub fn is_possible(black_nums: Vec<i32>) -> bool { let (mut black_cnt, mut black_tails) = (std::collections::HashMap::new(), std::collections::HashMap::new()); for &x in &black_nums { *black_cnt.entry(x).or_insert(0) += 1; } for &x in &black_nums { if *black_cnt.get(&x).unwrap_or(&0) == 0 { continue; } *black_cnt.get_mut(&x).unwrap() -= 1; if *black_tails.get(&(x - 1)).unwrap_or(&0) > 0 { *black_tails.get_mut(&(x - 1)).unwrap() -= 1; *black_tails.entry(x).or_insert(0) += 1; } else if *black_cnt.get(&(x + 1)).unwrap_or(&0) > 0 && *black_cnt.get(&(x + 2)).unwrap_or(&0) > 0 { *black_cnt.get_mut(&(x + 1)).unwrap() -= 1; *black_cnt.get_mut(&(x + 2)).unwrap() -= 1; *black_tails.entry(x + 2).or_insert(0) += 1; } else { return false; } } true } }